import getpass
import hashlib
import os

class Сотрудник:
    def __init__(self, имя, пароль):
        self.имя = имя
        self.пароль = hashlib.sha256(пароль.encode()).hexdigest()

    def проверить_пароль(self, пароль):
        return hashlib.sha256(пароль.encode()).hexdigest() == self.пароль

class Система_защиты:
    def __init__(self):
        self.сотрудники = {}

    def добавить_сотрудника(self, имя, пароль):
        if имя not in self.сотрудники:
            self.сотрудники[имя] = Сотрудник(имя, пароль)
            print(f"Сотрудник {имя} добавлен.")
        else:
            print(f"Сотрудник {имя} уже существует.")

    def удалить_сотрудника(self, имя):
        if имя in self.сотрудники:
            del self.сотрудники[имя]
            print(f"Сотрудник {имя} удален.")
        else:
            print(f"Сотрудник {имя} не существует.")

    def авторизоваться(self, имя, пароль):
        if имя in self.сотрудники:
            if self.сотрудники[имя].проверить_пароль(пароль):
                print(f"Авторизация успешна. Вы вошли как {имя}.")
                return True
            else:
                print("Неправильный пароль.")
                return False
        else:
            print("Сотрудник не существует.")
            return False
